from typing import List
from collections import defaultdict, deque

class Solution:
    def areSentencesSimilarTwo(self, sentence1: List[str], sentence2: List[str], similarPairs: List[List[str]]) -> bool:
        if len(sentence1) != len(sentence2):
            return False

        # Build the graph
        graph = defaultdict(list)
        for x, y in similarPairs:
            graph[x].append(y)
            graph[y].append(x)

        # BFS to find if two words are similar
        def areSimilar(word1, word2):
            if word1 == word2:
                return True
            visited = set()
            queue = deque([word1])
            while queue:
                current = queue.popleft()
                if current == word2:
                    return True
                visited.add(current)
                for neighbor in graph[current]:
                    if neighbor not in visited:
                        queue.append(neighbor)
            return False

        # Check each pair of words in the sentences
        for w1, w2 in zip(sentence1, sentence2):
            if not areSimilar(w1, w2):
                return False

        return True
```

This solution uses a graph to represent the similarity relationships between words. Each word is a node, and an edge exists between two nodes if the corresponding words are similar. We then perform a Breadth-First Search (BFS) to determine if two words are similar, taking advantage of the transitive property of similarity. If any pair of words at the same position in the two sentences are not similar, the sentences are not similar overall.
